INSERT INTO cats (cat_id, name, breed, personality, bio, zoomies_per_hour, naps_per_day, judginess_level, favorite_product_id, img_name) VALUES
(1, 'Sir Fluffington III', 'British Shorthair', 'Lawful Nap', 'Retired from active zoomie duty at age two. Now spends his days judging your posture and filing formal complaints about empty bowls.', 0.3, 18, 9, 5, NULL),
(2, 'Princess Keyboard Smash', 'Siamese', 'Chaotic Treat-Seeker', 'Managed to send 47 emails to her owner''s boss by walking across the keyboard. Currently under investigation for insider trading.', 7.2, 11, 7, 10, NULL),
(3, 'Dave the DevOps Cat', 'Tabby', 'Lawful Chaos', 'Pushes to production at 3am and blames the dog. Maintains a five-nines uptime on his nap schedule. On-call rotation: always.', 2.1, 14, 6, 4, NULL),
(4, 'Madame Overfed', 'Persian', 'Neutral Floof', 'Has not seen her paws since 2022 but describes herself as big-boned. Moonlights as a decorative throw pillow. Fully embraces the role.', 0.1, 20, 8, 1, NULL),
(5, 'Professor Nap-a-lot', 'Maine Coon', 'True Neutral', 'Holds three PhDs, all in sleep science. Lectures are delivered entirely in purrs. Students report a 100% attendance rate because nobody dares to disturb him.', 1.0, 22, 5, 6, NULL),
(6, 'Zoomie McZoomface', 'Bengal', 'Chaotic Evil', 'The only cat on record to have lapped the living room 400 times in a single evening. Sponsored by a local chiropractor. No regrets.', 14.8, 6, 3, 12, NULL),
(7, 'Lady Biscuit Paws', 'Ragdoll', 'Lawful Good', 'Makes biscuits on every available surface including laptops, faces, and once, a birthday cake. Certified emotional support animal — for herself.', 2.5, 16, 4, 8, NULL),
(8, 'Whiskerton von Judgement', 'Scottish Fold', 'Neutral Evil', 'Stares into your soul during video calls. HR has received three complaints. Unapologetic. Currently authoring a memoir titled "You Disappoint Me."', 1.7, 13, 10, 3, NULL);
